import React from "react";
import styled from "styled-components";
import emailjs from "emailjs-com";

import Panel from "./panel";
import Button from "./button";

class ContactPanel extends React.Component {
  handleSubmit = (e) => {
    e.preventDefault();

    emailjs
      .sendForm(
        "service_bp7joj7", // Service ID
        "template_gmn0yg5", // Template ID
        e.target,
        "user_pxUfYL4KJtfRC2tvUcxVC" // User ID
      )
      .then(
        (result) => {
          console.log(result.text);
        },
        (error) => {
          console.log(error.text);
        }
      );
    e.target.reset();
  };

  render() {
    return (
      <Panel color={this.props.colors.panel}>
        <TitleRow>
          <Title color={this.props.colors.heading}>Contact Me</Title>
        </TitleRow>
        <BodyContainer>
          <Form onSubmit={this.handleSubmit}>
            <SenderInfoRow>
              <SenderInfoInput
                type="text"
                placeholder="Your name"
                name="name"
                required
              />
              <SenderInfoInput
                type="email"
                placeholder="Your email"
                name="email"
                required
              />
            </SenderInfoRow>
            <MessageRow>
              <MessageInput
                id="contactMessage"
                type="text"
                placeholder="Want to connect, collaborate, or critique? Send me a message!"
                name="message"
                required
              />
            </MessageRow>
            <SubmitRow>
              <SubmittedText color={this.props.colors.button_text}>
                {" "}
                Submitted!
              </SubmittedText>
              <Button
                type="submit"
                value="Submit"
                backgroundColor={this.props.colors.panel}
                borderColor={this.props.colors.button_border}
                textColor={this.props.colors.button_text}
                hoverBackgroundColor={this.props.colors.main}
              >
                Submit
              </Button>
            </SubmitRow>
          </Form>
        </BodyContainer>
      </Panel>
    );
  }
}

export default ContactPanel;

/* START: TITLE */
const TitleRow = styled.div`
  display: flex;
  flex-direction: column;
  margin: 0 2rem;
  font-family: "Fraunces", serif;
`;

const Title = styled.h2`
  position: relative;
  display: block;
  margin: 0 3rem;
  text-align: right;
  font-size: 6rem;
  color: ${(props) => props.color};
  line-height: 6rem;
`;
/* END: TITLE */

